```python
import functools

def deco(func):
    @functools.wraps(func)
    def wrapper(*args, **kwargs):
        return func(*args, **kwargs)
    return wrapper

@deco
def saludo(nombre: str) -> str:
    """Devuelve un saludo."""
    return f"Hola, {nombre}"

print(saludo.__name__)
print(saludo.__doc__)
print(saludo.__annotations__)
```
